@import url('https://fonts.googleapis.com/css2?family=Chivo&display=swap');

.theme-fandomdesktop-light, .theme-fandomdesktop-dark {
    --theme-body-background-image: url('https://static.wikia.nocookie.net/backrooms/images/9/9a/Level_11.3_bg.png/revision/latest?cb=20260605132643');
}
.theme-fandomdesktop-light {
    --theme-page-background-color: #e7e7efdd;
    --theme-page-background-color--secondary: #f7f7ffee;
    --theme-page-text-color: #202027;
    --theme-page-accent-mix-color: #cad0e8;
    --theme-community-header-color: #0f0f0f;
    --theme-link-color: #4a77af;
	--theme-accent-color: #85b0cf;
    --theme-accent-label-color: #ffffff;
    --theme-border-color: #9495a8;
	--theme-sticky-nav-background-color: #60a0bf;
    --quote: #dfdfe7;
    --bquote: #bbbbbf;
    --dot-dot: rgba(20, 25, 30, 0.15);
    --shadow: #dddddd;

    .darkblock {
      background-color: transparent;
      backdrop-filter: brightness(0.47);
      color: var(--theme-page-background-color);
    }
    .darkblock h1, .darkblock h2, .darkblock h3, .darkblock h4 {
      filter: brightness(2);
    }
}

.theme-fandomdesktop-dark {
    --theme-page-background-color: #1c1c1ddd;
    --theme-page-background-color--secondary: #333334ee;
    --theme-page-text-color: #efeff5;
    --theme-page-accent-mix-color: #405f66;
    --theme-community-header-color: #ffffff;
    --theme-link-color: #a0dfef;
	--theme-accent-color: #80afba;
    --theme-accent-label-color: #ffffff;
    --theme-border-color: #607fb0;
	--theme-sticky-nav-background-color: #192536;
    --quote: #575760;
    --bquote: #66677d;
    --dot-dot: rgba(40, 45, 58, 0.9);
    --shadow: #111219;

    .darkblock {
      background-color: transparent;
      backdrop-filter: brightness(0.8);
    }
}
html .resizable-container, .page {
  Font-family: 'Chivo', Sans-serif;
}
.page-content {
  text-align: justify;
}
.page-content, .fandom-community-header {
  animation: fadeup 1s ease-in-out;
}
@keyframes fadeup {
  from {
    transform: translateY(15px);
    opacity: 0;
  }
  to {
    transform: translateY(0);
    opacity: 1;
  }
}
.styled-quote {
  background-color: var(--quote) !important;
  border-color: var(--bquote) !important;
}
h1 {
    font-weight: 600;
    color: var(--theme-link-color);
    font-family: 'Staatliches', Serif;
    letter-spacing: 2px;
    word-spacing: 4px;
}
.page-content h1, .page-content h2, .page-content h3 {
    font-family: 'Staatliches', Serif;
    font-weight: 600;
    color: var(--theme-link-color);
    letter-spacing: 2px;
    word-spacing: 4px;
}
.titleblock {
  border-color: var(--theme-page-accent-mix-color);
  background-color: var(--quote);
}
.theme-fandomdesktop-dark .fandom-community-header,
.theme-fandomdesktop-light .fandom-community-header {
    background-image: linear-gradient(transparent, var(--theme-page-background-color));
    margin-bottom: -12px;
    padding: 1em 2em;
    font-family: 'Staatliches', Serif;
    letter-spacing: 2px;
    word-spacing: 4px;
}

.right-rail-wrapper, .page__main, .lightblock, .styled-quote {
	background-image: radial-gradient(var(--dot-dot) 1px, transparent 1px), radial-gradient(var(--dot-dot) 1px, transparent 1px);
	background-size: 30px 30px;
	background-position: 0 0, 15px 15px;
}

.rail-module {
	background: none;
}

a {
  text-shadow: 0 0 0 var(--theme-link-color), 0 0 0 var(--theme-link-color);
  padding-bottom: 2px;
  transition: 0.3s ease-out;
  color: var(--theme-link-color);
}

a:hover,
a:focus-visible {
  text-shadow: 0 1px 0 var(--theme-page-text-color), 0 -1px 0 var(--theme-page-text-color);
  font-weight: bold;
  color: var(--theme-page-text-color)
}
.fandom-community-header__image img { opacity: 0; }
.fandom-community-header__image:before {
    content: '';
    background: url(https://static.wikia.nocookie.net/backrooms/images/2/22/Level_11.3_logo.png/revision/latest?cb=20260607153654) no-repeat;
    margin: 0.9rem 0 0rem 0rem;
    width: 100px;
    height: 112px;
    background-size: 97px;
    position: absolute;
    transition: 0s;
}

